import static org.eclipse.rdf4j.sail.lmdb.LmdbDistinctCursorSkipTestSupport.firstStatementPattern;
import static org.eclipse.rdf4j.sail.lmdb.LmdbDistinctCursorSkipTestSupport.shutDownAndDelete;
