import org.junit.jupiter.api.io.TempDir;

class LmdbDistinctCursorSkipSafeScopeTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void distinctSubjectFilterNotExistsUsesCursorSkipWhenSkippedOrgIsUnobserved(@TempDir File dataDir)
			throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			IRI memberOf = VF.createIRI("urn:distinct:not-exists:memberOf");
			IRI revoked = VF.createIRI("urn:distinct:not-exists:revokedMembership");
			Set<Value> expectedSubjects = new LinkedHashSet<>();

			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin();
				for (int subjectIndex = 0; subjectIndex < 4; subjectIndex++) {
					IRI subject = VF.createIRI("urn:distinct:not-exists:s:" + subjectIndex);
					if (subjectIndex != 2) {
						expectedSubjects.add(subject);
					}
					for (int orgIndex = 0; orgIndex < 12; orgIndex++) {
						connection.add(subject, memberOf, VF.createIRI("urn:distinct:not-exists:org:" + orgIndex));
					}
				}
				connection.add(VF.createIRI("urn:distinct:not-exists:s:2"), revoked,
						VF.createIRI("urn:distinct:not-exists:revocation"));
				connection.commit();
				store.getBackingStore().getSketchBasedJoinEstimator().rebuild();
				LmdbPlannerAwait.awaitSketchesReady(store);

				String query = """
						SELECT DISTINCT ?s WHERE {
						  ?s <urn:distinct:not-exists:memberOf> ?org
						  FILTER NOT EXISTS { ?s <urn:distinct:not-exists:revokedMembership> ?event }
						}
						""";
				Set<Value> resultSubjects = new LinkedHashSet<>();
				try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
					while (result.hasNext()) {
						resultSubjects.add(result.next().getValue("s"));
					}
				}
				assertEquals(expectedSubjects, resultSubjects);

				Explanation explanation = explain(connection, query);
				StatementPattern pattern = patternWithPredicate(explanation, memberOf);
				assertNotNull(pattern, explanation::toString);
				assertUsesCursorSkip(pattern, explanation);
				assertTrue(pattern.getSourceRowsScannedActual() <= 6L,
						"Correlated NOT EXISTS should not force scanning duplicate organizations:\n" + explanation);
			}
		} finally {
			shutDownAndDelete(repository, dataDir);
		}
	}

	@Test
	void distinctPredicateOrderByProjectedVarLimitUsesCursorSkip(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin();
				for (int predicateIndex = 0; predicateIndex < 5; predicateIndex++) {
					IRI predicate = VF.createIRI("urn:distinct:ordered-limit:p:" + predicateIndex);
					for (int row = 0; row < 12; row++) {
						connection.add(VF.createIRI("urn:distinct:ordered-limit:s:" + predicateIndex + ":" + row),
								predicate, VF.createIRI("urn:distinct:ordered-limit:o:" + row));
					}
				}
				connection.commit();
				store.getBackingStore().getSketchBasedJoinEstimator().rebuild();
				LmdbPlannerAwait.awaitSketchesReady(store);

				String query = "SELECT DISTINCT ?p WHERE { ?s ?p ?o } ORDER BY ?p LIMIT 3";
				int rowCount = 0;
				try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
					while (result.hasNext()) {
						result.next();
						rowCount++;
					}
				}
				assertEquals(3, rowCount);

				Explanation explanation = explain(connection, query);
				StatementPattern pattern = firstStatementPattern((TupleExpr) explanation.tupleExpr());
				assertNotNull(pattern, explanation::toString);
				assertUsesCursorSkip(pattern, explanation);
				assertTrue(pattern.getSourceRowsScannedActual() <= 7L,
						"ORDER BY projected DISTINCT var should retain cursor skip:\n" + explanation);
			}
		} finally {
			shutDownAndDelete(repository, dataDir);
		}
	}

	private StatementPattern patternWithPredicate(Explanation explanation, IRI predicate) {
		return statementPatterns((TupleExpr) explanation.tupleExpr()).stream()
				.filter(pattern -> predicate.equals(pattern.getPredicateVar().getValue()))
				.findFirst()
				.orElse(null);
	}
}
